const body = $input.first().json.body;
const fb = body.feedback;

const prompt = `Analysiere dieses Kundenfeedback und antworte NUR als JSON.

Feedback:
- Autor: ${fb.author}
- Kategorie: ${fb.category}
- Bewertung: ${fb.rating}/5 Sterne
- Text: "${fb.text}"

Antworte in exakt diesem JSON-Format (kein Markdown, kein Erklärungstext):
{
  "sentiment": "positive" | "neutral" | "negative",
  "keywords": ["max. 5 relevante Schlüsselwörter auf Deutsch"],
  "summary": "Eine Satz Zusammenfassung auf Deutsch (max. 15 Wörter)"
}

Sentiment-Regeln:
- positive: Bewertung 4-5 UND überwiegend positiver Ton
- negative: Bewertung 1-2 ODER starke Kritik/Frustration
- neutral: Bewertung 3 oder gemischte Aussagen`;

return [{ json: { prompt, feedbackId: fb.id } }];

const aiText = $input.first().json.message?.content || '{}';
const feedbackId = $('Prompt aufbauen').first().json.feedbackId;

let parsed;
try {
  const cleaned = aiText.replace(/```json\n?/g,'').replace(/```/g,'').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { sentiment: 'neutral', keywords: [], summary: 'Analyse fehlgeschlagen.' };
}

// Validierung
const validSentiments = ['positive', 'neutral', 'negative'];
if (!validSentiments.includes(parsed.sentiment)) parsed.sentiment = 'neutral';
if (!Array.isArray(parsed.keywords)) parsed.keywords = [];
parsed.keywords = parsed.keywords.slice(0, 5); // max 5

return [{ json: {
  sentiment: parsed.sentiment,
  keywords: parsed.keywords,
  summary: parsed.summary || '',
  feedbackId
}}];
